    """
    Execute a tiny SELECT-only SQL fragment over an in-memory table of rows.

    Supported grammar:
    SELECT <columns> FROM rows [WHERE <column> <op> <int>] [LIMIT <int>]

    Args:
        query: SQL query string
        rows: List of dictionaries representing table rows

    Returns:
        List of dictionaries matching the query
    """

    # Helper function to validate column names
    def validate_columns(columns, available_columns):
        """Check if all requested columns exist in the table."""
        for col in columns:
            if col not in available_columns:
                raise ValueError(f"Unknown column: {col}")

