        try:
            value = int(value_str)
        except ValueError:
            raise ValueError("WHERE clause value must be an integer")

        # Create filter function based on operator
        if op == '=':
            return lambda row: row.get(column) == value
        elif op == '!=':
            return lambda row: row.get(column) != value
        elif op == '<':
            return lambda row: row.get(column) < value
        elif op == '>':
