import ast

class BoundedEvaluator(ast.NodeVisitor):
    def __init__(self, variables, max_nodes):
        self.variables = variables
        self.max_nodes = max_nodes
        self.node_count = 0

    def visit(self, node):
        if self.node_count >= self.max_nodes:
            raise ValueError("Expression exceeds maximum allowed nodes")
        self.node_count += 1
        return super().visit(node)

    def visit_Module(self, node):
        if len(node.body) != 1:
            raise ValueError("Only single expression is allowed")
        return self.visit(node.body[0])

    def visit_Expr(self, node):
        return self.visit(node.value)

    def visit_BinOp(self, node):
        left = self.visit(node.left)
        right = self.visit(node.right)
        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.FloorDiv):
            return left // right
        else:
            raise ValueError("Unsupported binary operation")

    def visit_UnaryOp(self, node):
        operand = self.visit(node.operand)
        if isinstance(node.op, ast.USub):
            return -operand
        else:
            raise ValueError("Unsupported unary operation")

    def visit_Num(self, node):
        return node.n

    def visit_Name(self, node):
        if node.id in self.variables:
            return self.variables[node.id]
        else:
            raise ValueError(f"Unknown variable: {node.id}")

    def visit_ParenExpr(self, node):
        return self.visit(node.value)

    def generic_visit(self, node):
        raise ValueError("Unsupported expression")

def bounded_evaluate(expression: str, variables: dict[str, int], max_nodes: int = 32) -> int:
    try:
        tree = ast.parse(expression, mode='eval')
        evaluator = BoundedEvaluator(variables, max_nodes)
        return evaluator.visit(tree)
    except Exception as e:
        raise ValueError(f"Invalid expression: {e}")

